// FIX: collect all enriched providers after loop completes
const items = $input.all().map(i => i.json);

return [{
  json: {
    providers: items,
    request: $('Format Response4').first().json.request,
    recommendations: $('Format Response4').first().json.recommendations,
  }
}];

const requestBody = {
  budget:$input.first().json.budget ,
  event_type: $json.event_type,
  city: $json.city,
  top_k: $json.top_k,
};

return [{ json: { ...$json, requestBody } }];

// FIX: preserve request context + flatten recommendations
const apiResponse = $json;
const input = $('Build Request Body4').first().json;
const result = apiResponse.result || apiResponse || {};
const recommendations = result.recommendations || [];

return [{
  json: {
    request: {
      budget: input.budget,
      event_type: input.event_type,
      city: input.city,
      top_k: input.top_k,
    },
    recommendations: recommendations.map(p => ({
      provider_id: p.provider_id,
      provider: p.provider,
      provider_service_type: p.provider_service_type || '-',
      city: p.city,
      avg_price: p.avg_price,
      fit_score: p.fit_score,
      price_gap: p.price_gap,
    }))
  }
}];

// FIX: merge audit + AI reply + enriched recommendations
const base = $('Format Response4').first().json;
const audit = $('Store Audit Record2').first().json;
const aiReply = $input.first().json?.output || $input.first().json?.text || '';

// Enrichir les recommendations avec les données MySQL (provider_service_type)
const mysqlProviders = $('Aggregate Providers').first().json?.providers || [];

const enrichedRecs = base.recommendations.map(rec => {
  const mysqlMatch = mysqlProviders.find(p =>
    String(p.id_provider) === String(rec.provider_id)
  );
  return {
    ...rec,
    provider_service_type: mysqlMatch?.service_type
      || mysqlMatch?.provider_service_type
      || mysqlMatch?.type
      || rec.provider_service_type
      || 'N/A',
    phone:    mysqlMatch?.phone    || '',
    email:    mysqlMatch?.email    || '',
    website:  mysqlMatch?.website  || '',
  };
});

// Nettoyer le markdown de l'AI pour le front
const cleanAI = aiReply
  .replace(/\*\*(.*?)\*\*/g, '$1')       // bold
  .replace(/\*(.*?)\*/g, '$1')           // italic
  .replace(/#+\s?/g, '')                 // headings
  .replace(/\|[-| ]+\|[\r\n]?/g, '')    // table separator rows
  .replace(/^\|\s?/gm, '')              // table leading pipe
  .replace(/\s?\|$/gm, '')              // table trailing pipe
  .replace(/\n{3,}/g, '\n\n')           // extra blank lines
  .trim();

return [{
  json: {
    status: 'success',
    request: base.request,
    recommendations: enrichedRecs,
    audit: {
      saved:              !!audit.saved,
      record_id:          audit.record_id ?? null,
      alert_recommended:  !!audit.alert_recommended,
      alert_reasons:      audit.alert_reasons || [],
    },
    ai_package_suggestion: cleanAI,
    table: {
      headers: ['Provider', 'Provider Service Type', 'City', 'Avg Price', 'Gap', 'Fit Score'],
      rows: enrichedRecs.map(p => ([
        p.provider,
        p.provider_service_type,
        p.city,
        Number(p.avg_price).toLocaleString('fr-TN', { style: 'currency', currency: 'TND', maximumFractionDigits: 0 }),
        Number(p.price_gap).toLocaleString('fr-TN',  { style: 'currency', currency: 'TND', maximumFractionDigits: 0 }),
        `${Number(p.fit_score).toFixed(1)}%`,
      ]))
    }
  },
}];
